INSERT INTO `chat_messages` VALUES (1,1,'user','hello',NULL,NULL,'2026-03-04 09:05:21'),(2,1,'bot','Xin lỗi, tôi chưa có câu trả lời.',NULL,NULL,'2026-03-04 09:05:21'),(3,1,'user','Thư viện mở cửa lúc mấy giờ?',NULL,NULL,'2026-03-04 09:18:00'),(4,1,'bot','Xin lỗi, tôi chưa có câu trả lời.',NULL,NULL,'2026-03-04 09:18:00'),(5,5,'user','hi',NULL,NULL,'2026-03-04 09:41:12'),(6,5,'bot','Xin lỗi, tôi chưa có câu trả lời.',NULL,NULL,'2026-03-04 09:41:12'),(7,6,'user','Thư viện mở cửa lúc mấy giờ?',NULL,NULL,'2026-03-04 09:42:53'),(8,6,'bot','Xin lỗi, tôi chưa có câu trả lời.',NULL,NULL,'2026-03-04 09:42:53'),(9,6,'user','Làm thế nào để mượn sách?',NULL,NULL,'2026-03-04 09:52:20'),(10,6,'bot','Để mượn sách, bạn cần có thẻ thư viện hợp lệ. Mang sách đến quầy mượn/trả và xuất trình thẻ thư viện. Bạn có thể mượn tối đa 5 cuốn sách trong 14 ngày.',1,1.0000,'2026-03-04 09:52:20'),(11,6,'user','mở cửa mấy giờ',NULL,NULL,'2026-03-04 09:52:48'),(12,6,'bot','Thư viện mở cửa từ 7:30 đến 21:00 các ngày trong tuần (Thứ 2 - Thứ 7). Chủ nhật nghỉ.',4,1.0000,'2026-03-04 09:52:48'),(13,6,'user','có bán bánh khong',NULL,NULL,'2026-03-04 09:54:04'),(14,6,'bot','Xin lỗi, tôi chưa có câu trả lời cho câu hỏi này. Bạn có thể liên hệ thủ thư để được hỗ trợ.',NULL,NULL,'2026-03-04 09:54:04'),(15,6,'user','Làm thẻ thư viện ở đâu?',NULL,NULL,'2026-03-04 09:57:42'),(16,6,'bot','Bạn có thể đăng ký làm thẻ thư viện tại quầy tiếp nhận (tầng 1). Cần mang theo CMND/CCCD và 1 ảnh 3x4. Phí làm thẻ là 50.000đ.',3,1.0000,'2026-03-04 09:57:42'),(17,7,'user','h\'',NULL,NULL,'2026-03-04 10:43:30'),(18,7,'bot','Xin lỗi, tôi chưa có câu trả lời cho câu hỏi này. Bạn có thể liên hệ thủ thư để được hỗ trợ.',NULL,NULL,'2026-03-04 10:43:30'),(19,7,'user','có bán bánh bò không',NULL,NULL,'2026-03-04 10:43:44'),(20,7,'bot','Xin lỗi, tôi chưa có câu trả lời cho câu hỏi này. Bạn có thể liên hệ thủ thư để được hỗ trợ.',NULL,NULL,'2026-03-04 10:43:44'),(21,7,'user','cách mượn sách',NULL,NULL,'2026-03-04 10:52:37'),(22,7,'bot','Để mượn sách, bạn cần có thẻ thư viện hợp lệ. Mang sách đến quầy mượn/trả và xuất trình thẻ thư viện. Bạn có thể mượn tối đa 5 cuốn sách trong 14 ngày.',1,1.0000,'2026-03-04 10:52:37'),(23,7,'user','có đồ ăn sáng không',NULL,NULL,'2026-03-04 10:54:22'),(24,7,'bot','Có ờ ngây tầng trệt vào cửa quẹo',6,1.0000,'2026-03-04 10:54:22'),(25,7,'user','có mì ly không',NULL,NULL,'2026-03-04 10:54:38'),(26,7,'bot','Có ờ ngây tầng trệt vào cửa quẹo',6,1.0000,'2026-03-04 10:54:38'),(27,7,'user','hello',NULL,NULL,'2026-03-04 13:15:50'),(28,7,'bot','Xin lỗi, tôi chưa có câu trả lời cho câu hỏi này. Bạn có thể liên hệ thủ thư để được hỗ trợ.',NULL,NULL,'2026-03-04 13:15:50'),(29,7,'user','tôi cần tư vấn',NULL,NULL,'2026-03-04 13:16:01'),(30,7,'bot','Xin lỗi, tôi chưa có câu trả lời cho câu hỏi này. Bạn có thể liên hệ thủ thư để được hỗ trợ.',NULL,NULL,'2026-03-04 13:16:01'),(31,7,'user','chức năng thư viện',NULL,NULL,'2026-03-04 13:16:23'),(32,7,'bot','CHỨC NĂNG CỦA CHATBOT THƯ VIỆN\nBao gồm các chức năng sau:\nPhía người dùng:\nChỉ cần truy cập vào website và nhấy chuột hoặc chọn vào biểu tượng chatbot. Và bắt đầu trò chuyện.\nChatbot trả lời những câu hỏi liên quan mà quản trị viên đưa vào hệ thống.\nPhía quản trị:\nCó quyền quản trị hệ thống, như thêm xóa sửa các bộ câu hỏi cho chatbot\nĐăng nhập với phân quyền cao nhất Google.\nQuản trị viên có thể cài đặt câu hỏi bằng nhiều phương thức như tải bộ dữ liệu bằng word, pdf hoặc gõ tay trực tiếp.\nCó thể tùy chỉnh màu sắc giao diện chatbot theo ý muốn, theo sự kiện trong năm.\nCó thể tắt hoặc hiển thị Chatbot theo ý thích.\nThu thập câu hỏi từ người dùng',NULL,1.0000,'2026-03-04 13:16:23'),(33,7,'user','chức năng của thư viện trường mình là gì',NULL,NULL,'2026-03-04 13:18:11'),(34,7,'bot','CHỨC NĂNG CỦA CHATBOT THƯ VIỆN\nBao gồm các chức năng sau:\nPhía người dùng:\nChỉ cần truy cập vào website và nhấy chuột hoặc chọn vào biểu tượng chatbot. Và bắt đầu trò chuyện.\nChatbot trả lời những câu hỏi liên quan mà quản trị viên đưa vào hệ thống.\nPhía quản trị:\nCó quyền quản trị hệ thống, như thêm xóa sửa các bộ câu hỏi cho chatbot\nĐăng nhập với phân quyền cao nhất Google.\nQuản trị viên có thể cài đặt câu hỏi bằng nhiều phương thức như tải bộ dữ liệu bằng word, pdf hoặc gõ tay trực tiếp.\nCó thể tùy chỉnh màu sắc giao diện chatbot theo ý muốn, theo sự kiện trong năm.\nCó thể tắt hoặc hiển thị Chatbot theo ý thích.\nThu thập câu hỏi từ người dùng',NULL,1.0000,'2026-03-04 13:18:11'),(35,7,'user','Thư viện mở cửa lúc mấy giờ?',NULL,NULL,'2026-03-04 13:21:10'),(36,7,'bot','Thư viện mở cửa từ 7:30 đến 21:00 các ngày trong tuần (Thứ 2 - Thứ 7). Chủ nhật nghỉ.',4,1.0000,'2026-03-04 13:21:10'),(37,8,'user','Tra cứu sách như thế nào?',NULL,NULL,'2026-03-04 14:11:19'),(38,8,'bot','Bạn có thể tra cứu sách qua hệ thống OPAC trên website thư viện hoặc tại các máy tính tra cứu đặt tại tầng 1.',5,1.0000,'2026-03-04 14:11:19'),(39,10,'user','Thư viện mở cửa lúc mấy giờ?',NULL,NULL,'2026-03-04 14:11:27'),(40,10,'bot','Thư viện mở cửa từ 7:30 đến 21:00 các ngày trong tuần (Thứ 2 - Thứ 7). Chủ nhật nghỉ.',4,1.0000,'2026-03-04 14:11:27'),(41,11,'user','luận án',NULL,NULL,'2026-03-04 14:16:37'),(42,11,'bot','Xin lỗi, tôi chưa có câu trả lời cho câu hỏi này. Bạn có thể liên hệ thủ thư để được hỗ trợ.',NULL,NULL,'2026-03-04 14:16:37'),(43,11,'user','luận án',NULL,NULL,'2026-03-04 14:57:29'),(44,11,'bot','Nộp lưu chiểu là việc nộp bản điện tử hoàn chỉnh (đã được duyệt sau góp ý của Hội đồng) của luận án, luận văn hoặc đề án sau bảo vệ để lưu trữ tại Trung tâm Học liệu và Hỗ trợ Học thuật, Trường Đại học Trà Vinh, theo Thông báo số 3356/TB-ĐHTV ngày 05/9/2025.',12,1.0000,'2026-03-04 14:57:29'),(45,11,'user','Làm thẻ thư viện ở đâu?',NULL,NULL,'2026-03-04 14:59:00'),(46,11,'bot','Bạn có thể đăng ký làm thẻ thư viện tại quầy tiếp nhận (tầng 1). Cần mang theo CMND/CCCD và 1 ảnh 3x4. Phí làm thẻ là 50.000đ.',3,1.0000,'2026-03-04 14:59:00'),(47,11,'user','hướng dẫn viết mail',NULL,NULL,'2026-03-04 15:08:00'),(48,11,'bot',