DROP TABLE IF EXISTS `event_themes`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `event_themes` (
  `id` int NOT NULL AUTO_INCREMENT,
  `theme_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Tên chủ đề (VD: Tết, Noel, Khai giảng...)',
  `theme_key` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'CSS class key (vd: tet, halloween...)',
  `primary_color` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '#1976D2' COMMENT 'Màu chính',
  `secondary_color` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '#FFFFFF' COMMENT 'Màu phụ',
  `header_bg_color` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '#1976D2' COMMENT 'Màu nền header',
  `header_text_color` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '#FFFFFF' COMMENT 'Màu chữ header',
  `user_bubble_color` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '#E3F2FD' COMMENT 'Màu bong bóng người dùng',
  `bot_bubble_color` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '#F5F5F5' COMMENT 'Màu bong bóng bot',
  `button_color` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '#1976D2' COMMENT 'Màu nút chatbot',
  `font_family` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT 'Roboto, sans-serif',
  `bot_avatar_url` text COLLATE utf8mb4_unicode_ci COMMENT 'Ảnh avatar chatbot',
  `decorations` text COLLATE utf8mb4_unicode_ci COMMENT 'Emoji/k├¢ tß╗▒ trang tr├¡ (JSON array)',
  `banner_text` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Nß╗Öi dung banner sß╗▒ kiß╗çn',
  `welcome_message` text COLLATE utf8mb4_unicode_ci COMMENT 'Tin nhắn chào mừng',
  `start_date` date DEFAULT NULL COMMENT 'Ngày bắt đầu áp dụng',
  `end_date` date DEFAULT NULL COMMENT 'Ngày kết thúc áp dụng',
  `is_active` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Đang được kích hoạt',
  `created_by` int DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `created_by` (`created_by`),
  CONSTRAINT `event_themes_ibfk_1` FOREIGN KEY (`created_by`) REFERENCES `admins` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=34 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Chủ đề giao diện chatbot theo sự kiện trong năm';
/*!40101 SET character_set_client = @saved_cs_client */;

