--
-- Table structure for table `questions`
--

DROP TABLE IF EXISTS `questions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `questions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `category_id` int DEFAULT NULL,
  `question_text` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Nội dung câu hỏi',
  `answer_text` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Nội dung trả lời',
  `answer_text_en` text COLLATE utf8mb4_unicode_ci,
  `source_type` enum('manual','word','pdf') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'manual' COMMENT 'Phương thức nhập',
  `dataset_id` int DEFAULT NULL COMMENT 'ID bộ dữ liệu nếu import từ file',
  `priority` int NOT NULL DEFAULT '0' COMMENT 'Độ ưu tiên hiển thị',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_by` int DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `category_id` (`category_id`),
  KEY `created_by` (`created_by`),
  KEY `dataset_id` (`dataset_id`),
  FULLTEXT KEY `ft_question` (`question_text`),
  FULLTEXT KEY `ft_answer` (`answer_text`),
  CONSTRAINT `questions_ibfk_1` FOREIGN KEY (`category_id`) REFERENCES `categories` (`id`) ON DELETE SET NULL,
  CONSTRAINT `questions_ibfk_2` FOREIGN KEY (`created_by`) REFERENCES `admins` (`id`) ON DELETE SET NULL,
  CONSTRAINT `questions_ibfk_3` FOREIGN KEY (`dataset_id`) REFERENCES `datasets` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=137 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Bộ câu hỏi và trả lời cho chatbot';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `questions`
--

LOCK TABLES `questions` WRITE;
/*!40000 ALTER TABLE `questions` DISABLE KEYS */;
INSERT INTO `questions` VALUES (1,8,'Làm thế nào để mượn sách?','Để mượn sách, bạn cần có thẻ thư viện hợp lệ. Mang sách đến quầy mượn/trả và xuất trình thẻ thư viện. Bạn có thể mượn tối đa 5 cuốn sách trong 14 ngày.','To borrow books, you need a valid library card. Bring the book to the borrowing/returning counter and present your library card. The staff will process the loan for you.\n\nBorrowing steps:\n1. Find the book you want to borrow\n2. Bring it to the circulation desk\n3. Present your reader card\n4. Receive the book and due date slip','manual',NULL,0,1,NULL,'2026-03-04 09:51:16','2026-03-06 13:12:37'),(2,1,'Thời hạn mượn sách là bao lâu?','Thời hạn mượn sách là 14 ngày. Bạn có thể gia hạn thêm 7 ngày nếu sách chưa có người đặt trước.','The borrowing period is 14 days. You can renew for an additional 7 days if no one has reserved the book.\n\nNote:\n- Category 1 (students): 14 days, up to 5 books\n- Category 2 (faculty/staff): 30 days\n- Category 3 (external readers): 14 days with deposit required','manual',NULL,0,1,NULL,'2026-03-04 09:51:16','2026-03-06 13:12:37'),(3,2,'Làm thẻ thư viện ở đâu?','Bạn có thể đăng ký làm thẻ thư viện tại quầy tiếp nhận (tầng 1). Cần mang theo CMND/CCCD và 1 ảnh 3x4. Phí làm thẻ là 50.000đ.','You can register for a library card at the reception counter (1st floor). You need to bring your ID card/Citizen ID and one 3x4 photo.\n\nRegistration process:\n1. Go to the reception desk on the 1st floor\n2. Fill out the registration form\n3. Submit your ID and photo\n4. Receive your library card','manual',NULL,0,1,NULL,'2026-03-04 09:51:16','2026-03-06 13:12:37'),(4,4,'Thư viện mở cửa lúc mấy giờ?','Thư viện mở cửa từ 7:30 đến 21:00 các ngày trong tuần (Thứ 2 - Thứ 7). Chủ nhật nghỉ.','The library is open from 7:30 AM to 9:00 PM on weekdays (Monday - Saturday). Closed on Sundays.\n\nNote: Operating hours may vary by area within the center.','manual',NULL,0,1,NULL,'2026-03-04 09:51:16','2026-03-06 13:12:37'),(5,3,'Làm sao tra cứu sách trên hệ thống?','Bạn có thể tra cứu sách qua hệ thống OPAC trên website thư viện hoặc tại các máy tính tra cứu đặt tại tầng 1.','You can search for books through the OPAC system on the library website or at the search computers located on the 1st floor. Visit: https://opac.tvu.edu.vn\n\nSearch steps:\n1. Access the OPAC website\n2. Log in with your reader account\n3. Enter the book title or keyword\n4. View search results and note the call number\n5. Find the book on the shelf','manual',NULL,0,1,NULL,'2026-03-04 09:51:16','2026-03-06 13:12:37'),(6,8,'Có bán đồ ăn vặt không','Có ờ ngây tầng trệt vào cửa quẹo ','Yes, there are snacks available on the ground floor near the entrance.','manual',NULL,0,1,1,'2026-03-04 10:54:09','2026-03-06 13:12:37'),(12,7,'Nộp lưu chiểu luận án, luận văn, đề án là gì?','Nộp lưu chiểu là việc nộp bản điện tử hoàn chỉnh (đã được duyệt sau góp ý của Hội đồng) của luận án, luận văn hoặc đề án sau bảo vệ để lưu trữ tại Trung tâm Học liệu và Hỗ trợ Học thuật, Trường Đại học Trà Vinh, theo Thông báo số 3356/TB-ĐHTV ngày 05/9/2025.','Submitting archival copies means submitting the complete electronic version (approved after the defense council\'s feedback) of your thesis, dissertation, or project for archival at the Learning Resource Center.\n\nThis is a mandatory requirement after successful defense.','word',13,0,1,2,'2026-03-04 14:55:36','2026-03-06 13:12:37'),(13,7,'Ai phải nộp lưu chiểu luận văn, luận án, đề án?','Đối tượng thực hiện gồm: Nghiên cứu sinh và học viên cao học (gọi chung là người học) đã bảo vệ thành công tại Trường Đại học Trà Vinh.','The submission requirement applies to: Research students and graduate students (collectively referred to as learners) who have successfully defended their thesis/dissertation/project.\n\nThis includes:\n- Doctoral students (dissertations)\n- Master\'s students (theses)\n- Students completing banking projects (SBV projects)','word',13,0,1,2,'2026-03-04 14:55:36','2026-03-06 13:12:37'),(14,7,'Nộp lưu chiểu bằng hình thức nào?','Bản điện tử hoàn chỉnh định dạng PDF, gửi qua email tiepnhanlvla@tvu.edu.vn.','Submit the complete electronic version in PDF format, sent via email to tiepnhanlvla@tvu.edu.vn.\n\nRequirements:\n- PDF format\n- Single file\n- Must be the approved final version after defense','word',13,0,1,2,'2026-03-04 14:55:36','2026-03-06 13:12:37'),(15,8,'Gửi file đến email nào?','tiepnhanlvla@tvu.edu.vn.','Send your file to: tiepnhanlvla@tvu.edu.vn','word',13,0,1,2,'2026-03-04 14:55:36','2026-03-06 13:12:37'),(16,NULL,'File phải ở định dạng gì?','File PDF, lưu thành một tập tin duy nhất.','The file must be in PDF format, saved as a single file.\n\nImportant:\n- Only PDF format is accepted\n- Combine all pages into one file\n- File name must follow the prescribed format','word',13,0,1,2,'2026-03-04 14:55:36','2026-03-06 13:12:37'),(17,8,'Khi nào bắt đầu nộp?','Từ ngày 10/9/2025.','Starting from September 10, 2025.\n\nPlease ensure you submit your archival copy promptly after your defense.','word',13,0,1,2,'2026-03-04 14:55:36','2026-03-06 13:12:37'),(18,8,'Dùng email nào để gửi?','Phải dùng email đã đăng ký với Nhà trường từ đầu khóa học. Không chấp nhận nộp thay.','You must use the email registered with the University at the beginning of your program. Submissions from other emails will not be accepted.\n\nNote: Proxy submissions are not allowed.','word',13,0,1,2,'2026-03-04 14:55:36','2026-03-06 13:12:37'),(19,8,'Có được nộp thay không?','Không. Người học phải tự gửi.\nPHẦN 2: QUY CÁCH EMAIL VÀ FILE','No. Learners must submit the archival copy themselves. Proxy submissions are not accepted.','word',13,0,1,2,'2026-03-04 14:55:36','2026-03-06 13:12:37'),(20,8,'Viết tiêu đề email thế nào?','[Mã số học viên] – [Tên loại tài liệu: LUAN AN/LUAN VAN/DE AN SBV] – [HỌ VÀ TÊN].Viết hoa, không dấu, có khoảng cách.Ví dụ: 910117001 – DE AN SBV - NGUYEN VAN A','Email subject format: [Student ID] – [Document type: LUAN AN/LUAN VAN/DE AN SBV] – [FULL NAME]\n\nWrite in uppercase, without diacritical marks.\n\nExample: 910117001 – DE AN SBV – NGUYEN VAN A','word',13,0,1,2,'2026-03-04 14:55:36','2026-03-06 13:12:37'),(21,8,'Đặt tên file đính kèm thế nào?','Giống tiêu đề email. Viết hoa, không dấu.\nVí dụ cụ thể:Tiêu đề: 910117001 – DE AN SBV - NGUYEN VAN ATên file: 910117001 – DE AN SBV - NGUYEN VAN A.pdf\nCó được chia nhiều file không?Trả lời: Không. Chỉ một file PDF duy nhất.\nPHẦN 3: QUY CÁCH FILE LUẬN VĂN / ĐỀ ÁN THẠC SĨ\nFile gồm các phần:\nTrang bìa chính\nTrang phụ bìa\nQuyết định giao đề tài (nếu có)\nLời cam đoan\nLời cảm ơn\nMục lục\nDanh mục bảng/hình/chữ viết tắt\nTrang tóm tắt\nNội dung luận văn\nDanh mục tài liệu tham khảo\nPhụ lục\nBiên bản liên quan\nBiên bản gồm:\nBiên bản họp Hội đồng\nBản giải trình chỉnh sửa\nCó cần quyết định giao đề tài không?Trả lời: Có.\nThứ tự sắp xếp:Bìa → Phụ bìa → Quyết định → Cam đoan → Cảm ơn → Mục lục → Danh mục → Tóm tắt → Nội dung → Tài liệu tham khảo → Phụ lục → Biên bản.\nPHẦN 4: QUY CÁCH FILE LUẬN ÁN TIẾN SĨ\nFile gồm:\nTrang bìa chính\nTrang phụ bìa\nLời cam đoan\nLời cảm ơn\nMục lục\nDanh mục bảng/hình/chữ viết tắt\nTrang tóm tắt\nNội dung luận án\nDanh mục tài liệu tham khảo\nPhụ lục\nBiên bản liên quan\nBiên bản gồm:\nQuyết định thành lập hội đồng\nBiên bản họp đánh giá\nBản giải trình chỉnh sửa\nKhác nhau giữa thạc sĩ và tiến sĩ:\nThạc sĩ: Có Quyết định giao đề tài\nTiến sĩ: Không có Quyết định giao đề tài\nPHẦN 5: LIÊN HỆ HỖ TRỢ\nLiên hệ:Trung tâm Học liệu và Hỗ trợ Học thuật - Trường Đại học Trà VinhEmail: tiepnhanlvla@tvu.edu.vnĐiện thoại: (0294) 3855 246 - nội bộ 385Địa chỉ: Tòa nhà B7 - Khu I, Trường Đại học Trà Vinh\nSố điện thoại: (0294) 3855 246 - nội bộ 385\nĐịa chỉ trực tiếp: Tòa nhà B7 - Khu I, Trường Đại học Trà Vinh\nEmail: tiepnhanlvla@tvu.edu.vn\nCăn cứ văn bản:\nThông báo 3630/TB-ĐHTV ngày 01/11/2021\nThông báo 3356/TB-ĐHTV ngày 05/9/2025','Name the attached file the same as the email subject. Write in uppercase, without diacritical marks.\n\nExample: 910117001 – DE AN SBV – NGUYEN VAN A.pdf','word',13,0,1,2,'2026-03-04 14:55:36','2026-03-06 13:12:37'),(22,7,'Quy định này áp dụng cho ai?','Áp dụng cho tất cả cá nhân tham gia sử dụng hoạt động phục vụ Bạn đọc tại Trung tâm Học liệu - Phát triển Dạy và Học thuộc Trường Đại học Trà Vinh.','This regulation applies to all individuals participating in and using the services of the Learning Resource and Academic Support Center at Tra Vinh University.\n\nThis includes students, faculty, staff, and external visitors.','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(23,3,'Tài nguyên thông tin là gì?','Là tập hợp tài liệu in, viết tay, nghe nhìn, tài liệu số, vi phim, vi phiếu, tài liệu cho người khuyết tật và các dữ liệu khác.','Information resources refer to the collection of printed materials, handwritten documents, audiovisual materials, digital documents, microfilm, microfiche, and other formats containing information stored at the Center.\n\nThese resources serve learning, teaching, and research purposes.','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(24,3,'Tài nguyên thông tin mở là gì?','Là tài nguyên mà người dùng có thể tiếp cận mà không bị rào cản tài chính, pháp lý hoặc kỹ thuật.','Open information resources are resources that users can access without financial or technical barriers.\n\nThese include open-access databases, e-journals, and digital repositories available through the Center\'s website.','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(25,7,'Quá hạn là gì?','Là giao dịch mượn tài liệu đã vượt quá thời gian quy định.','An overdue transaction is a book loan that has exceeded the prescribed borrowing period.\n\nOverdue materials are subject to fines. Please return or renew your books on time to avoid penalties.','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(26,7,'Gia hạn là gì?','Là việc kéo dài thêm thời gian mượn tài liệu khi sắp đến hạn trả.','Renewal is the process of extending the borrowing period for a document when the due date is approaching.\n\nYou can renew:\n- Category 1 & 3: 15 additional days\n- Category 2: 30 additional days\n- Only 1 renewal is allowed per loan\n- Cannot renew if already overdue','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(27,7,'Có mấy nhóm đối tượng sử dụng Trung tâm?','Đối tượng 1: Học sinh, sinh viên, học viên, lưu học sinh.\nĐối tượng 2: Viên chức, người lao động, tình nguyện viên.\nĐối tượng 3: Giảng viên thỉnh giảng, cựu sinh viên và cá nhân ngoài trường.','There are 3 user categories at the Center:\n\n- Category 1: Students, graduate students, international students\n- Category 2: Faculty, staff, and employees of the University\n- Category 3: External readers (individuals outside the University)\n\nEach category has different borrowing privileges and requirements.','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(28,7,'Thẻ bạn đọc dùng để làm gì?','Dùng để đăng ký sử dụng dịch vụ, mượn, trả và gia hạn tài liệu.','The reader card is used to register for services, borrow, return, and renew library materials.\n\nIt serves as your identity for all library transactions. Please keep it safe and do not lend it to others.','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(29,7,'Tài khoản bạn đọc dùng để làm gì?','Dùng để:\nĐăng nhập máy tính\nTra cứu tài liệu\nXem tài liệu trực tuyến','The reader account is used to:\n- Log in to library computers\n- Search for materials in the catalog\n- View online resources\n- Access licensed databases\n- Manage your borrowing history','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(30,7,'Làm sao để được cấp tài khoản?','Đối tượng 1: Tài khoản gửi qua email trường.\nĐối tượng 2, 3: Liên hệ quầy lưu hành hoặc email lrc@tvu.edu.vn.','How to get an account:\n- Category 1: Account will be sent to your university email\n- Category 2 & 3: Contact the circulation desk to register\n\nYour account gives you access to all digital services of the Center.','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(31,1,'Đối tượng 3 mượn sách có cần đặt cọc không?','\n Đối tượng 3 mượn sách có cần đặt cọc không?\nCó. Đặt cọc số tiền gấp 2 lần giá bìa. Hoàn lại khi trả sách đúng quy định.','Yes. Category 3 readers (external readers) must place a deposit equal to twice the cover price of the book. The deposit will be refunded upon return of the book in good condition.','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 13:12:37'),(32,1,'Gia hạn được bao nhiêu ngày?','Đối tượng 1 và 3: 15 ngày.\nĐối tượng 2: 30 ngày.','Renewal periods:\n- Category 1 and 3: 15 days\n- Category 2: 30 days\n\nNote: Only one renewal is allowed per loan.','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(33,1,'Gia hạn được mấy lần?','Chỉ được gia hạn 1 lần và chưa bị quá hạn.','You can only renew once, and the book must not be overdue at the time of renewal.\n\nIf the book is already overdue, you must return it and pay the overdue fine before borrowing again.','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(34,1,'Phạt quá hạn bao nhiêu tiền?','2.000 đồng/quyển/ngày.','The overdue fine is 2,000 VND per book per day.\n\nPlease return your books on time to avoid accumulating fines.','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(35,3,'Làm sao để tra cứu tài liệu?','Truy cập website: https://opac.tvu.edu.vn → Đăng nhập → Tìm kiếm tài liệu.','How to search for materials:\n1. Visit the website: https://opac.tvu.edu.vn\n2. Log in with your reader account\n3. Search for materials by title, author, or keyword\n4. Note the call number and shelf location\n5. Find the material on the shelf or request assistance','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(36,4,'Có thể sử dụng tài nguyên mở ở đâu?','Trên website https://celri.tvu.edu.vn với các nguồn như SpringerOpen, DOAJ, ScienceDirect,...','You can access open resources on the website https://celri.tvu.edu.vn with sources such as Springer, DOAJ, and other open-access databases.\n\nThese resources are freely available to all users.','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(37,1,'Muốn dùng cơ sở dữ liệu bản quyền phải làm sao?','Liên hệ quầy lưu hành để được cấp tài khoản.','To use licensed databases, contact the circulation desk to get an account.\n\nLicensed databases provide access to premium academic journals, e-books, and research papers.','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(38,3,'Scan tài liệu được bao nhiêu phần trăm?','Tối đa 10% tổng số trang hoặc dung lượng.','You can scan up to 10% of the total pages or content of a document.\n\nThis limit is in accordance with copyright regulations. For larger amounts, please consult with the librarian.','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(39,4,'Trung tâm mở cửa khi nào?','Thứ Hai đến Chủ nhật (trừ tối Chủ nhật).\nTừ 7:00 đến 21:00 tùy khu vực.','The Center is open:\n- Monday to Sunday (except Sunday evenings)\n- From 7:00 AM to 9:00 PM depending on the area\n\nPlease check the specific schedule for each floor/section.','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(40,3,'Bạn đọc có quyền gì?','Sử dụng các dịch vụ Trung tâm.\nYêu cầu hỗ trợ tra cứu.\nTham gia hoạt động do Trung tâm tổ chức.','Readers have the right to:\n- Use all services provided by the Center\n- Request assistance with searching for materials\n- Participate in activities organized by the Center\n- Provide feedback and suggestions\n- Access digital resources through their reader account','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(41,9,'Làm mất sách xử lý thế nào?','Đền sách mới + phí xử lýHoặc\nBồi thường gấp 2 lần giá bìa + phí xử lý(Tài liệu quý hiếm: gấp 10 lần giá bìa)','If you lose a book, you must:\n- Provide a replacement copy (same edition) + processing fee, OR\n- Compensate twice the cover price + processing fee\n\nThe processing fee is 50,000 VND per book. Please report lost books promptly.','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-09 07:33:22'),(42,1,'Làm hư hỏng tài liệu xử lý thế nào?','Phạt 100% giá bìa + phí xử lý 50.000 đồng.','If you damage library materials:\n- Fine: 100% of the cover price + processing fee of 50,000 VND\n\nPlease handle all library materials with care to preserve them for other users.','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(43,1,'Có thể bị khóa tài khoản không?','Có.\nVi phạm nhẹ: khóa 1 tháng\nVi phạm nặng: khóa 3 tháng\nTái phạm nhiều lần: đình chỉ 1 năm hoặc vĩnh viễn','Yes, your account can be locked for violations:\n- Minor violations: locked for 1 month\n- Serious violations: locked for 3 months\n- Repeat offenses: locked for 6 months or permanently\n\nPlease follow all library rules and regulations.','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(44,5,'Trung tâm có khen thưởng không?','Có. Trung tâm đề xuất khen thưởng Bạn đọc có đóng góp tích cực.','Yes. The Center recommends commendations for readers who make positive contributions.\n\nThis may include recognition for:\n- Active participation in library programs\n- Outstanding use of resources\n- Contributions to the library community','word',14,0,1,2,'2026-03-04 15:36:08','2026-03-06 16:41:56'),(45,NULL,'hello','“Xin chào bạn, Trung tâm Học liệu và Hỗ trợ Học thuật - Trường Đại học Trà Vinh rất vui được hỗ trợ bạn. Bạn cần chúng tôi hỗ trợ thông tin gì hôm nay ạ?”','Hello! Welcome to the Learning Resource and Academic Support Center at Tra Vinh University. We\'re happy to assist you today! ?\n\nHow can we help you? You can ask about:\n? Borrowing books\n? Searching for materials\n? Library regulations\n⏰ Opening hours\n? Digital resources','manual',NULL,0,1,2,'2026-03-04 16:25:17','2026-03-06 13:12:37'),(46,NULL,'xin chào','Chào mừng đến với thư viện TVU. Mình giúp được gì cho bạn ?','Welcome to the TVU Library! How can I help you today? ?\n\nFeel free to ask about:\n? Book borrowing and returning\n? Material searching\n? Library policies\n⏰ Operating hours\n? Online resources','manual',NULL,0,1,2,'2026-03-05 13:47:20','2026-03-06 13:12:37'),(88,8,'Phòng Tài liệu Nội sinh nằm ở đâu?','Phòng Tài liệu Nội sinh nằm tại phòng B71.302 ở tầng 3.','','word',18,0,1,2,'2026-03-06 16:30:23','2026-03-09 07:28:13'),(104,9,'Trung tâm Học liệu và Hỗ trợ Học thuật nằm ở tòa nhà nào?','Trung tâm Học liệu và Hỗ trợ Học thuật nằm tại tòa nhà B71.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:30:55'),(105,9,'Sơ đồ Trung tâm Học liệu được cập nhật vào ngày nào?','Sơ đồ Trung tâm Học liệu và Hỗ trợ Học thuật được cập nhật ngày 6/3/2026.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:30:46'),(106,9,'Tầng trệt của Trung tâm Học liệu có những khu vực nào?','Tầng trệt có Hội trường B71.101, Quầy Lưu hành 1 (mượn – trả sách), Ban Hỗ trợ Học thuật B71.102, Phòng Tự học 1 B71.103 và khu vực tự học ngoài sảnh.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:30:29'),(107,9,'Hội trường của Trung tâm Học liệu nằm ở đâu?','Hội trường nằm tại phòng B71.101 ở tầng trệt.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:30:22'),(108,9,'Quầy mượn và trả sách ở tầng trệt nằm ở đâu?','Quầy Lưu hành 1 tại tầng trệt là nơi thực hiện mượn và trả sách.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:28:48'),(109,9,'Ban Hỗ trợ Học thuật nằm ở phòng nào?','Ban Hỗ trợ Học thuật nằm tại phòng B71.102 ở tầng trệt.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:30:04'),(110,9,'Phòng Tự học 1 nằm ở đâu?','Phòng Tự học 1 nằm tại phòng B71.103 ở tầng trệt.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:29:56'),(111,9,'Tầng 2 có những phòng nào?','Tầng 2 gồm Phòng Học liệu Quốc văn 1 (B71.201), Phòng Nghiên cứu 1 (B71.202), Phòng Tự học 2 (B71.203), Phòng Nghiên cứu 2 (B71.204), Phòng Học liệu Quốc văn 2 (B71.205), Quầy Lưu hành 2 (mượn – trả sách) và khu vực tự học ngoài sảnh.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:29:49'),(112,9,'Phòng Học liệu Quốc văn 1 nằm ở đâu?','Phòng Học liệu Quốc văn 1 nằm tại phòng B71.201 ở tầng 2.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:29:38'),(113,9,'Phòng Nghiên cứu 1 nằm ở đâu?','Phòng Nghiên cứu 1 nằm tại phòng B71.202 ở tầng 2.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:29:27'),(114,9,'Phòng Tự học 2 nằm ở đâu?','Phòng Tự học 2 nằm tại phòng B71.203 ở tầng 2.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:29:21'),(115,9,'Phòng Nghiên cứu 2 nằm ở đâu?','Phòng Nghiên cứu 2 nằm tại phòng B71.204 ở tầng 2.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:29:11'),(116,9,'Phòng Học liệu Quốc văn 2 nằm ở đâu?','Phòng Học liệu Quốc văn 2 nằm tại phòng B71.205 ở tầng 2.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:29:02'),(117,9,'Quầy mượn trả sách ở tầng 2 nằm ở đâu?','Quầy Lưu hành 2 tại tầng 2 là nơi thực hiện mượn và trả sách.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:31:29'),(118,9,'Tầng 3 có những khu vực nào?','Tầng 3 có Phòng Học liệu Ngoại văn (B71.301), Phòng Tài liệu Nội sinh (B71.302), Quầy Lưu hành 3 và khu vực tự học ngoài sảnh.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:31:36'),(119,9,'Phòng Học liệu Ngoại văn nằm ở đâu?','Phòng Học liệu Ngoại văn nằm tại phòng B71.301 ở tầng 3.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:31:44'),(120,9,'Phòng Tài liệu Nội sinh chứa những loại tài liệu gì?','Phòng Tài liệu Nội sinh lưu trữ luận văn, luận án, đề án, đồ án tốt nghiệp và tạp chí.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:31:52'),(121,9,'Quầy Lưu hành 3 dùng để làm gì?','Quầy Lưu hành 3 dùng để mượn – trả sách và đăng ký tài khoản sử dụng Phòng Học liệu Điện tử.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:32:01'),(122,9,'Tầng 4 có những phòng nào?','Tầng 4 có Phòng Học liệu Điện tử (B71.401), Phòng Tự học 4 và Phòng Học nhóm (B71.402) cùng khu vực tự học ngoài sảnh.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:32:09'),(123,9,'Phòng Học liệu Điện tử có những gì?','Phòng Học liệu Điện tử có máy tính, wifi và cho phép truy cập các cơ sở dữ liệu số.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:32:16'),(124,9,'Phòng Học liệu Điện tử nằm ở đâu?','Phòng Học liệu Điện tử nằm tại phòng B71.401 ở tầng 4.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:32:39'),(125,9,'Phòng Tự học 4 và phòng học nhóm nằm ở đâu?','Phòng Tự học 4 và phòng học nhóm nằm tại phòng B71.402 ở tầng 4.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:32:53'),(126,9,'Tầng 5 có những phòng nào?','Tầng 5 có Phòng Giám đốc (B71.501), Phòng Lưu hành và Phó Giám đốc (B71.502), Phòng họp (B71.503), Phòng Kỹ thuật và Phát triển tài liệu số (B71.504), Phòng Nghiệp vụ - Biên mục (B71.505), Ban Phát triển chương trình (B71.506 và B71.507), Phòng tập huấn (B71.508) và khu vực tự học ngoài sảnh.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:30:13'),(127,9,'Phòng Giám đốc nằm ở đâu?','Phòng Giám đốc nằm tại phòng B71.501 ở tầng 5.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:33:01'),(128,9,'Phòng Lưu hành và Phó Giám đốc nằm ở đâu?','Phòng Lưu hành và Phó Giám đốc nằm tại phòng B71.502 ở tầng 5.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:33:08'),(129,NULL,'Phòng Kỹ thuật và Phát triển tài liệu số nằm ở đâu?','Phòng này nằm tại phòng B71.504 ở tầng 5.',NULL,'word',19,0,1,2,'2026-03-06 16:40:49','2026-03-06 16:40:49'),(130,NULL,'Phòng Nghiệp vụ - Biên mục nằm ở đâu?','Phòng Nghiệp vụ - Biên mục nằm tại phòng B71.505 ở tầng 5.',NULL,'word',19,0,1,2,'2026-03-06 16:40:49','2026-03-06 16:40:49'),(131,NULL,'Ban Phát triển chương trình nằm ở đâu?','Ban Phát triển chương trình nằm tại phòng B71.506 và B71.507 ở tầng 5.',NULL,'word',19,0,1,2,'2026-03-06 16:40:49','2026-03-06 16:40:49'),(132,NULL,'Phòng tập huấn nằm ở đâu?','Phòng tập huấn nằm tại phòng B71.508 ở tầng 5.',NULL,'word',19,0,1,2,'2026-03-06 16:40:49','2026-03-06 16:40:49'),(133,9,'Tầng 6 có những khu vực nào?','Tầng 6 có Phòng Tự học 5 (B71.601) và khu tự học sân thượng.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:31:06'),(134,9,'Phòng Tự học 5 nằm ở đâu?','Phòng Tự học 5 nằm tại phòng B71.601 ở tầng 6.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:31:12'),(135,9,'Trung tâm Học liệu có khu tự học sân thượng không?','Có, khu tự học sân thượng nằm tại tầng 6.','','word',19,0,1,2,'2026-03-06 16:40:49','2026-03-09 07:31:22');
