DROP TABLE IF EXISTS `suggested_questions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `suggested_questions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `question_text` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Câu hỏi gợi ý hiển thị cho người dùng',
  `linked_question_id` int DEFAULT NULL COMMENT 'Liên kết đến câu hỏi có sẵn',
  `sort_order` int NOT NULL DEFAULT '0',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `linked_question_id` (`linked_question_id`),
  CONSTRAINT `suggested_questions_ibfk_1` FOREIGN KEY (`linked_question_id`) REFERENCES `questions` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Câu hỏi gợi ý hiển thị khi người dùng mở chatbot';
/*!40101 SET character_set_client = @saved_cs_client */;

