--
-- Table structure for table `unanswered_questions`
--

DROP TABLE IF EXISTS `unanswered_questions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `unanswered_questions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `session_id` int DEFAULT NULL,
  `question_text` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Câu hỏi người dùng mà bot không trả lời được',
  `frequency` int NOT NULL DEFAULT '1' COMMENT 'Số lần được hỏi',
  `is_resolved` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Đã được xử lý chưa',
  `resolved_by` int DEFAULT NULL,
  `resolved_at` datetime DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `session_id` (`session_id`),
  KEY `resolved_by` (`resolved_by`),
  CONSTRAINT `unanswered_questions_ibfk_1` FOREIGN KEY (`session_id`) REFERENCES `chat_sessions` (`id`) ON DELETE SET NULL,
  CONSTRAINT `unanswered_questions_ibfk_2` FOREIGN KEY (`resolved_by`) REFERENCES `admins` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=32 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Lưu câu hỏi mà chatbot không trả lời được để admin bổ sung';
/*!40101 SET character_set_client = @saved_cs_client */;

